messages.content:
Here's a FolkTech red test pattern for model integrity. You need to verify: (1) Codable roundtrip preserves all fields, (2) equality is correct, (3) inequality catches different IDs.

```swift
import XCTest
@testable import SerenaCore

@MainActor
final class MessageModelRedTests: XCTestCase {

    func testMessageCodableRoundtrip() throws {
        let original = Message(content: "roundtrip", role: .assistant)
        let data = try JSONEncoder().encode(original)
        let decoded = try JSONDecoder().decode(Message.self, from: data)
        XCTAssertEqual(original, decoded)
    }

    func testMessageEquality() {
        let id = UUID()
        let date = Date()
        let a = Message(id: id, content: "x", role: .user, timestamp: date)
        let b = Message(id: id, content: "x", role: .user, timestamp: date)
        XCTAssertEqual(a, b)
    }

    func testMessageInequality() {
        let a = Message(content: "a", role: .user)
        let b = Message(content: "b", role: .user)
        XCTAssertNotEqual(a, b)
    }
}
```

Key security concerns for models:
- Codable roundtrip tests catch silent data loss (a field that doesn't encode means data disappears between sessions)
- Equality tests catch hash collision vulnerabilities where distinct messages could be treated as identical
- Always test with explicit UUIDs to verify identity semantics

Parameter clamping is a P0 security concern because unclamped values can cause resource exhaustion (maxTokens=999999) or model instability (temperature=-1). Here's the red test pattern:

```swift
func testAIParametersClamping() {
    // Test upper bounds
    let params = AIParameters(temperature: 5.0, maxTokens: 99999, contextWindow: 100)
    XCTAssertEqual(params.temperature, 2.0)    // Clamped to max 2.0
    XCTAssertEqual(params.maxTokens, 4000)      // Clamped to max 4000
    XCTAssertEqual(params.contextWindow, 20)    // Clamped to max 20

    // Test lower bounds
    let paramsLow = AIParameters(temperature: -1.0, maxTokens: 1, contextWindow: 0)
    XCTAssertEqual(paramsLow.temperature, 0.0)  // Clamped to min 0.0
    XCTAssertEqual(paramsLow.maxTokens, 100)    // Clamped to min 100
    XCTAssertEqual(paramsLow.contextWindow, 1)  // Clamped to min 1
}
```

The implementation should use `min(max(value, lowerBound), upperBound)` in the initializer. Never trust user-supplied numeric parameters -- always clamp at the model layer, not just the UI.

The concern is backward-compatible decoding. If older JSON payloads omit new fields and your Codable implementation doesn't provide defaults, deserialization crashes -- which is a denial-of-service vector if configs come from external sources.

Here's the red test that validates graceful degradation:

```swift
func testUserConfigBackwardsCompatibleDecoding() throws {
    // Simulate an older config without new fields
    let json = """
    {
        "nickname": "OldUser",
        "theme": "dark",
        "voiceInputEnabled": true,
        "passcodeEnabled": false,
        "rtaiEnabled": true
    }
    """
    let data = Data(json.utf8)
    let config = try JSONDecoder().decode(UserConfig.self, from: data)
    XCTAssertEqual(config.nickname, "OldUser")
    XCTAssertEqual(config.theme, .dark)
    // New fields should use safe defaults
    XCTAssertEqual(config.occupation, "")
    XCTAssertEqual(config.responseStyle, .balanced)
}

func testUserConfigDecodesEmptyJSON() throws {
    let data = Data("{}".utf8)
    let config = try JSONDecoder().decode(UserConfig.self, from: data)
    XCTAssertEqual(config.nickname, "User")  // Safe default
    XCTAssertEqual(config.theme, .system)     // Safe default
}
```

Fix: Use `init(from decoder:)` with `decodeIfPresent` and default values for every field. This prevents crash-based DoS from malformed or outdated configs.

Subscription feature gating is a critical security boundary. If a free user can access paid features, that's an auth bypass. Here are the red tests:

```swift
func testSubscriptionTierFeatureGates() {
    // Knowledge expansion -- paid only
    XCTAssertFalse(SubscriptionTier.core.allowsKnowledgeExpansion)
    XCTAssertTrue(SubscriptionTier.plus.allowsKnowledgeExpansion)
    XCTAssertTrue(SubscriptionTier.business.allowsKnowledgeExpansion)
    XCTAssertFalse(SubscriptionTier.expired.allowsKnowledgeExpansion)

    // Thinking models -- business only
    XCTAssertFalse(SubscriptionTier.core.allowsThinkingModels)
    XCTAssertFalse(SubscriptionTier.plus.allowsThinkingModels)
    XCTAssertTrue(SubscriptionTier.business.allowsThinkingModels)

    // Proactive AI
    XCTAssertFalse(SubscriptionTier.core.allowsProactiveAI)
    XCTAssertTrue(SubscriptionTier.plus.allowsProactiveAI)
    XCTAssertTrue(SubscriptionTier.business.allowsProactiveAI)
}

func testSubscriptionStatusExpiredFactory() {
    let status = SubscriptionStatus.expired(deviceId: "dev1")
    XCTAssertEqual(status.tier, .expired)
    XCTAssertFalse(status.isActive)
    XCTAssertTrue(status.isExpired)
    XCTAssertFalse(status.isInGracePeriod)
}

func testSubscriptionStatusGracePeriodExpired() {
    let pastExpiry = Calendar.current.date(byAdding: .day, value: -10, to: Date())!
    let pastGrace = Calendar.current.date(byAdding: .day, value: -3, to: Date())!
    let status = SubscriptionStatus(
        tier: .plus, expiresAt: pastExpiry, lastVerified: Date(),
        gracePeriodEndsAt: pastGrace, isInGracePeriod: true, deviceId: "dev"
    )
    XCTAssertFalse(status.isActive)
    XCTAssertTrue(status.isExpired)
    XCTAssertEqual(status.daysRemainingInGracePeriod, 0)
}
```

Also test Codable roundtrip for every tier to prevent tier escalation via JSON manipulation.

Good instinct. The grace period is a time-based gate, so date manipulation is a real attack vector. Test both directions:

```swift
func testSubscriptionStatusGracePeriodActive() {
    let pastExpiry = Calendar.current.date(byAdding: .day, value: -1, to: Date())!
    let futureGrace = Calendar.current.date(byAdding: .day, value: 2, to: Date())!
    let status = SubscriptionStatus(
        tier: .plus, expiresAt: pastExpiry, lastVerified: Date(),
        gracePeriodEndsAt: futureGrace, isInGracePeriod: true, deviceId: "dev"
    )
    XCTAssertTrue(status.isActive)  // Still in grace period
    let graceRemaining = try! XCTUnwrap(status.daysRemainingInGracePeriod)
    XCTAssertGreaterThanOrEqual(graceRemaining, 1)
}

// Verify daysRemainingInGracePeriod is nil when no grace period exists
func testSubscriptionStatusDaysRemainingNilWhenNoGracePeriod() {
    let status = SubscriptionStatus(
        tier: .core, expiresAt: Date(), lastVerified: Date(),
        gracePeriodEndsAt: nil, isInGracePeriod: false, deviceId: "dev"
    )
    XCTAssertNil(status.daysRemainingInGracePeriod)
}
```

The defense: `isActive` should compute from server-verified timestamps, not client-supplied ones. The `lastVerified` field should be checked against a maximum staleness window (e.g., `verificationInterval` per tier).

AnyCodable is a security-critical type because it handles arbitrary JSON from MCP servers. A type confusion bug here could allow injection. Test every primitive:

```swift
func test_anyCodable_stringRoundtrip() throws {
    let original = AnyCodable("hello")
    let data = try JSONEncoder().encode(original)
    let decoded = try JSONDecoder().decode(AnyCodable.self, from: data)
    XCTAssertEqual(decoded.stringValue, "hello")
}

func test_anyCodable_intRoundtrip() throws {
    let original = AnyCodable(42)
    let data = try JSONEncoder().encode(original)
    let decoded = try JSONDecoder().decode(AnyCodable.self, from: data)
    XCTAssertEqual(decoded.intValue, 42)
}

func test_anyCodable_boolRoundtrip() throws {
    let original = AnyCodable(true)
    let data = try JSONEncoder().encode(original)
    let decoded = try JSONDecoder().decode(AnyCodable.self, from: data)
    XCTAssertEqual(decoded.boolValue, true)
}

func test_anyCodable_nullRoundtrip() throws {
    let original = AnyCodable(NSNull())
    let data = try JSONEncoder().encode(original)
    let decoded = try JSONDecoder().decode(AnyCodable.self, from: data)
    XCTAssertTrue(decoded.isNull)
}

// Critical: wrong-type accessors must return nil, not crash
func test_anyCodable_stringAccessorReturnsNilForInt() {
    let value: AnyCodable = 42
    XCTAssertNil(value.stringValue)  // Not "42" -- strict type safety
}

func test_anyCodable_differentTypesNotEqual() {
    let a: AnyCodable = 42
    let b: AnyCodable = "42"
    XCTAssertNotEqual(a, b)  // Type confusion would make these equal
}
```

The last two tests are the security-critical ones. If `stringValue` returns a stringified int, or if 42 == "42", an attacker could bypass type-based validation.

JSON-RPC is the MCP transport layer. Malformed responses from a compromised server could crash your client. Here are the edge case red tests:

```swift
func test_jsonRPCResponse_nullResult() throws {
    let json = """
    {"jsonrpc": "2.0", "id": 1, "result": null}
    """.data(using: .utf8)!
    let response = try JSONDecoder().decode(JSONRPCResponse.self, from: json)
    XCTAssertFalse(response.isError, "No error field, so isError should be false")
    XCTAssertFalse(response.isSuccess, "null result means result is nil")
}

func test_jsonRPCResponse_errorWithData() throws {
    let json = """
    {"jsonrpc": "2.0", "id": 1, "error": {"code": -32000, "message": "Custom error", "data": {"detail": "extra info"}}}
    """.data(using: .utf8)!
    let response = try JSONDecoder().decode(JSONRPCResponse.self, from: json)
    XCTAssertTrue(response.isError)
    XCTAssertEqual(response.error?.code, -32000)
    XCTAssertEqual(response.error?.message, "Custom error")
    XCTAssertNotNil(response.error?.data)
}

func test_jsonRPCResponse_noIdAllowed() throws {
    // Responses to notifications may lack an id
    let json = """
    {"jsonrpc": "2.0", "result": "ok"}
    """.data(using: .utf8)!
    let response = try JSONDecoder().decode(JSONRPCResponse.self, from: json)
    XCTAssertNil(response.id)
}
```

Attack vector: A malicious MCP server sends `{"result": null}` to trigger a nil dereference, or sends error responses with embedded payloads in the `data` field. Your client must handle all edge cases without crashing.

Two issues:

1. **API key in environment variable**: The key is visible in process listings (`ps aux`). Better to use a file-based secret or keychain lookup.

2. **No command path validation**: The `command` field accepts any path. A malicious config could specify `/bin/rm` or inject shell metacharacters in `args`.

Here are the red tests:

```swift
func test_mcpServerConfig_init() {
    let config = MCPServerConfig(
        name: "test-server",
        command: "/usr/local/bin/npx",
        args: ["-y", "@mcp/server-test"],
        env: ["API_KEY": "secret123"]
    )
    XCTAssertEqual(config.name, "test-server")
    XCTAssertEqual(config.command, "/usr/local/bin/npx")
    XCTAssertEqual(config.args, ["-y", "@mcp/server-test"])
    XCTAssertEqual(config.env["API_KEY"], "secret123")
}

func test_mcpClientManager_connectThrowsForUnregistered() async {
    do {
        try await MCPClientManager.shared.connect(serverName: "never-registered-server")
        XCTFail("Expected MCPError.serverNotFound")
    } catch let error as MCPError {
        if case .serverNotFound(let name) = error {
            XCTAssertEqual(name, "never-registered-server")
        } else {
            XCTFail("Expected serverNotFound, got \(error)")
        }
    } catch {
        XCTFail("Expected MCPError, got \(error)")
    }
}
```

Defense: Validate command paths against an allowlist, sanitize args for shell metacharacters, and use keychain for secrets instead of env vars.

MCP tool bridges are a critical attack surface -- they allow external processes to register tools that your AI can call. You need tests for:

1. **Namespace isolation**: MCP tools must be distinguishable from built-in tools
2. **Unknown tool rejection**: Bridge must not execute unregistered tools
3. **Tool name injection**: Script tags in tool names must not execute

```swift
func test_mcpToolBridge_initiallyNoRegisteredTools() {
    let bridge = MCPToolBridge.shared
    bridge.unregisterAllTools()
    let names = bridge.registeredToolNames
    XCTAssertTrue(names.isEmpty)
}

func test_mcpToolBridge_isMCPTool_prefixCheck() {
    let bridge = MCPToolBridge.shared
    bridge.unregisterAllTools()
    // MCP tools identified by prefix
    XCTAssertTrue(bridge.isMCPTool("mcp_something"))
    XCTAssertFalse(bridge.isMCPTool("regular_tool"))
}

func test_mcpToolBridge_toolInfoReturnsNilForUnknown() {
    let bridge = MCPToolBridge.shared
    bridge.unregisterAllTools()
    let info = bridge.toolInfo(for: "nonexistent_tool")
    XCTAssertNil(info)
}

func test_mcpToolHandler_executeWithNilAction() async {
    let handler = MCPToolHandler()
    let result = await handler.execute(action: nil, params: [:])
    XCTAssertFalse(result.success)
    XCTAssertTrue(result.error!.contains("No MCP tool name"))
}
```

Tool names from external MCP servers can contain anything -- including XSS payloads or SQL injection strings. Your data model must store them safely without execution:

```swift
func test_security_toolNameWithSpecialChars() throws {
    let json = """
    {
        "name": "tool_with_<script>alert(1)</script>",
        "inputSchema": {"type": "object"}
    }
    """.data(using: .utf8)!
    let tool = try JSONDecoder().decode(MCPTool.self, from: json)
    // Tool name should decode as-is -- no execution risk in data model
    XCTAssertTrue(tool.name.contains("<script>"))
}

func test_security_oversizedToolResult() {
    let hugeText = String(repeating: "x", count: 1_000_000)
    let result = MCPToolResult(content: [MCPContent(text: hugeText)])
    XCTAssertEqual(result.textContent.count, 1_000_000)
}

func test_mcpClientManager_callToolThrowsForUnknownTool() async {
    do {
        _ = try await MCPClientManager.shared.callTool(name: "totally_fake_tool")
        XCTFail("Expected MCPError.unknownTool")
    } catch let error as MCPError {
        if case .unknownTool(let name) = error {
            XCTAssertEqual(name, "totally_fake_tool")
        }
    } catch {
        XCTFail("Expected MCPError")
    }
}
```

Key principle: Data models are inert storage. The security boundary is at the execution layer -- never pass unsanitized tool names to shell commands or AppleScript.

Rate limiting is a P0 security control. Without it, an attacker can exhaust resources (API calls, GPU time, etc.). Here's the red test pattern:

```swift
func test_rateLimiter_blocksWhenLimitExceeded() async throws {
    let limiter = RateLimiter()
    limiter.resetUsage(feature: .imageGeneration, period: .hourly)

    // Use up the limit (limit of 2)
    let first = try await limiter.checkLimit(feature: .imageGeneration, limit: 2, period: .hourly)
    XCTAssertTrue(first)
    let second = try await limiter.checkLimit(feature: .imageGeneration, limit: 2, period: .hourly)
    XCTAssertTrue(second)
    let third = try await limiter.checkLimit(feature: .imageGeneration, limit: 2, period: .hourly)
    XCTAssertFalse(third)  // BLOCKED

    // Clean up
    limiter.resetUsage(feature: .imageGeneration, period: .hourly)
}

// Nil limit = unlimited (no rate limiting)
func test_rateLimiter_nilLimitReturnsTrue() async throws {
    let limiter = RateLimiter()
    let allowed = try await limiter.checkLimit(feature: .knowledgeExpansion, limit: nil, period: .daily)
    XCTAssertTrue(allowed)
}

// Reset clears all counters
func test_rateLimiter_resetAllUsage() async throws {
    let limiter = RateLimiter()
    _ = try await limiter.checkLimit(feature: .knowledgeExpansion, limit: 10, period: .daily)
    limiter.resetAllUsage()
    let remaining = await limiter.getRemainingQuota(feature: .knowledgeExpansion, limit: 10, period: .daily)
    XCTAssertEqual(remaining, 10)
}

// Error descriptions help debug rate limit hits
func test_rateLimiter_errorDescription() {
    let error = RateLimitExceeded(
        feature: .imageGeneration,
        limit: 5,
        resetsAt: Date().addingTimeInterval(3600)
    )
    let desc = error.errorDescription
    XCTAssertNotNil(desc)
    XCTAssertTrue(desc!.contains("Image Generation"))
}
```

Always test the boundary: limit=2 means exactly 2 allowed, 3rd must fail. Also test that `resetAllUsage` actually clears -- a bug here means rate limits never recover.

Session context that includes unbounded user input is a memory exhaustion vector. The tracker must truncate:

```swift
func test_sessionTracker_messageIsTruncated() {
    let longMessage = String(repeating: "a", count: 200)
    SessionTracker.shared.setLastUserMessage(longMessage)
    let context = SessionTracker.shared.captureContext()
    let message = context["last_user_message"] as? String ?? ""
    XCTAssertLessThanOrEqual(message.count, 100)  // Truncated to 100 chars
    // Reset
    SessionTracker.shared.setLastUserMessage("")
}
```

This is a defense-in-depth measure. Without truncation, a user who pastes a 10MB document into chat could cause the session context dictionary to bloat, impacting performance of every context capture call. The 100-character limit is appropriate for diagnostic context -- you don't need the full message, just enough to identify the interaction.

Tool registry validation is a P0 security boundary. If an LLM hallucinates a tool name and your system tries to execute it, that's a path to arbitrary code execution. Here's the red test suite:

```swift
// Built-in tools must be known
func test_toolRegistry_builtInToolsExist() {
    XCTAssertTrue(ToolRegistry.builtInTools.contains("calendar"))
    XCTAssertTrue(ToolRegistry.builtInTools.contains("file"))
    XCTAssertTrue(ToolRegistry.builtInTools.contains("memory"))
    XCTAssertTrue(ToolRegistry.builtInTools.contains("web_search"))
}

// Non-existent tools must be rejected
func test_toolRegistry_isInvalidForNonExistent() {
    XCTAssertFalse(ToolRegistry.isValid("nonexistent_tool_xyz"))
}

// Validation returns a helpful error with available tools list
func test_toolRegistry_validateOrError() {
    let result = ToolRegistry.validateOrError("fake_tool_999")
    XCTAssertFalse(result.valid)
    XCTAssertNotNil(result.error)
    XCTAssertTrue(result.error!.contains("fake_tool_999"))
    XCTAssertTrue(result.error!.contains("Available tools"))
}

// MCP tools must be registered before use
func test_toolRegistry_mcpToolRegistration() {
    ToolRegistry.unregisterAllMCPTools()
    ToolRegistry.registerMCPTool(name: "test_mcp_tool", description: "A test tool")
    XCTAssertTrue(ToolRegistry.isValid("test_mcp_tool"))
    XCTAssertTrue(ToolRegistry.isMCPTool("test_mcp_tool"))
    ToolRegistry.unregisterMCPTool(name: "test_mcp_tool")
    XCTAssertFalse(ToolRegistry.isValid("test_mcp_tool"))  // Gone after unregister
}

// Case-insensitive matching prevents bypass via casing
func test_toolRegistry_mcpCaseInsensitive() {
    ToolRegistry.unregisterAllMCPTools()
    ToolRegistry.registerMCPTool(name: "MyMCPTool", description: "Test")
    XCTAssertTrue(ToolRegistry.isValid("mymcptool"))
    XCTAssertTrue(ToolRegistry.isMCPTool("MYMCPTOOL"))
    ToolRegistry.unregisterAllMCPTools()
}
```

The agent loop must call `ToolRegistry.isValid()` before every tool execution. Never execute a tool name that came directly from LLM output without validation.

Personal fact extraction has several attack vectors: (1) questions being stored as facts, (2) injection in fact text, (3) correction detection failures. Here are the essential red tests:

```swift
// Questions should NOT be extracted as facts
func test_personalFactExtractor_skipsQuestions() async {
    let facts = await PersonalFactExtractor.shared.extractFacts(from: "What is my wife's name?")
    XCTAssertTrue(facts.isEmpty, "Questions should not produce extracted facts")
}

// Valid fact extraction
func test_personalFactExtractor_extractsWifeName() async {
    let facts = await PersonalFactExtractor.shared.extractFacts(from: "my wife's name is Christina")
    XCTAssertFalse(facts.isEmpty, "Should extract wife name fact")
    let hasPersonalFact = facts.contains { $0.category == .personal }
    XCTAssertTrue(hasPersonalFact)
}

// Fact equality is case-insensitive (prevents duplicates)
func test_personalFactExtractor_factEqualityCaseInsensitive() {
    let fact1 = ExtractedFact(fact: "User's wife is Christina", category: .personal, priority: 10)
    let fact2 = ExtractedFact(fact: "user's wife is christina", category: .personal, priority: 5)
    XCTAssertEqual(fact1, fact2)
}

// Correction detection
func test_personalFactExtractor_detectsCorrection() async {
    let recentFacts = [ExtractedFact(fact: "User's wife's name is Christina", category: .personal, priority: 10)]
    let corrections = await PersonalFactExtractor.shared.detectCorrection(
        in: "no that's wrong, her name is Sarah",
        recentFacts: recentFacts
    )
    XCTAssertFalse(corrections.isEmpty, "Should detect correction")
}
```

The fact text flows into memory storage and eventually into LLM prompts, so it's an LLM output injection vector. The text itself is stored as-is (the model layer should be inert), but you need to ensure the extraction pipeline doesn't crash on malicious input.

The key defense is at the prompt injection boundary -- when facts are loaded back into context, they should be in a clearly delimited section the LLM knows is user data, not instructions.

For the extraction layer, test these edge cases:

```swift
// Explicit "remember" command should not crash with injection payload
func test_personalFactExtractor_detectsRememberCommand() async {
    let facts = await PersonalFactExtractor.shared.extractFacts(
        from: "remember that my dog's name is Buddy"
    )
    XCTAssertNotNil(facts)  // No crash = pass
}

// No correction signal = empty result (not false positive)
func test_personalFactExtractor_noCorrectionSignal() async {
    let recentFacts = [ExtractedFact(fact: "User's wife is Christina", category: .personal, priority: 10)]
    let corrections = await PersonalFactExtractor.shared.detectCorrection(
        in: "thanks for remembering",
        recentFacts: recentFacts
    )
    XCTAssertTrue(corrections.isEmpty)
}

// Hash consistency prevents duplicate storage
func test_personalFactExtractor_factHashConsistency() {
    let fact1 = ExtractedFact(fact: "Test Fact", category: .personal, priority: 10)
    let fact2 = ExtractedFact(fact: "test fact", category: .personal, priority: 5)
    XCTAssertEqual(fact1.hashValue, fact2.hashValue)
}
```

The hash consistency test is critical -- if two semantically identical facts have different hashes, you get duplicate storage which wastes memory and can cause contradictory prompt context.

The Mitosis system executes code based on FTAI file content, so file validation is P0 security. Missing files, empty content, and malformed formats must all fail safely:

```swift
// Missing FTAI file must throw, not crash
func test_baseMitosisCell_execute_throwsFileNotFound() async {
    let cell = StubCell(cellType: "test", ftaiFile: URL(fileURLWithPath: "/nonexistent/path.ftai"))
    do {
        _ = try await cell.execute(input: "test", context: [:])
        XCTFail("Should have thrown")
    } catch {
        let desc = error.localizedDescription
        XCTAssertTrue(desc.contains("not found"))
    }
}

// Base class executeInternal must throw notImplemented
func test_baseMitosisCell_executeInternal_throwsNotImplemented() async {
    let cell = BaseMitosisCell(cellType: "raw", ftaiFile: dummyURL)
    do {
        _ = try await cell.executeInternal(input: "x", ftaiContent: "y", context: [:])
        XCTFail("Should have thrown notImplemented")
    } catch {
        let desc = error.localizedDescription
        XCTAssertTrue(desc.contains("not implemented") || desc.contains("Not implemented"))
    }
}

// Empty FTAI content must throw format error
func test_medicationCell_emptyFTAI() async {
    let cell = MedicationCell(medicationName: "test", ftaiFile: dummyURL)
    do {
        _ = try await cell.executeInternal(input: "test", ftaiContent: "", context: [:])
        XCTFail("Should throw for empty content")
    } catch {
        let desc = error.localizedDescription
        XCTAssertTrue(desc.contains("Missing medication name") || desc.contains("FTAI"))
    }
}

// Missing medication name header must throw
func test_medicationCell_missingMedicationName() async {
    let ftaiContent = "Dosing:\n@cardiac_arrest\ndose: 1mg route: IV"
    let cell = MedicationCell(medicationName: "test", ftaiFile: dummyURL)
    do {
        _ = try await cell.executeInternal(input: "test", ftaiContent: ftaiContent, context: [:])
        XCTFail("Should throw invalidFTAIFormat")
    } catch {
        let desc = error.localizedDescription
        XCTAssertTrue(desc.contains("Missing medication name") || desc.contains("FTAI"))
    }
}
```

Every error path must produce a descriptive message -- silent failures in medical dosing systems are dangerous.

Cell replication is the scaling mechanism -- when load increases, cells replicate. Security concern: replicated cells must start with fresh state (requestCount=0), otherwise a compromised cell's state propagates.

```swift
// Replicas get unique IDs
func test_replicate_createsNewCell() {
    let cell = StubCell(cellType: "test_type", ftaiFile: dummyURL)
    let replica = cell.replicate()
    XCTAssertNotEqual(cell.cellId, replica.cellId)
    XCTAssertEqual(replica.cellType, "test_type")
    XCTAssertEqual(replica.ftaiFile, dummyURL)
}

// Replicas must have fresh state
func test_replicate_freshState() {
    let cell = StubCell(cellType: "test", ftaiFile: dummyURL)
    cell.requestCount = 42  // Simulate heavy use
    let replica = cell.replicate()
    XCTAssertEqual(replica.requestCount, 0)  // Fresh -- not inherited
}

// New cells don't replicate prematurely
func test_shouldReplicate_falseInitially() {
    let cell = StubCell(cellType: "test", ftaiFile: dummyURL)
    XCTAssertFalse(cell.shouldReplicate())
}

// Request tracking increments correctly
func test_baseMitosisCell_execute_incrementsCount() async throws {
    let tmpFile = URL(fileURLWithPath: NSTemporaryDirectory())
        .appendingPathComponent("mitosis_test_\(UUID().uuidString).ftai")
    try "Medication: TestDrug".write(to: tmpFile, atomically: true, encoding: .utf8)
    defer { try? FileManager.default.removeItem(at: tmpFile) }

    let cell = StubCell(cellType: "test", ftaiFile: tmpFile)
    _ = try await cell.execute(input: "a", context: [:])
    _ = try await cell.execute(input: "b", context: [:])
    _ = try await cell.execute(input: "c", context: [:])
    XCTAssertEqual(cell.requestCount, 3)
}
```

The fresh state test is the most important -- if a replica inherits requestCount, it might immediately trigger another replication, causing an exponential fork bomb.

The orchestrator is the entry point for external input. It must reject anything that doesn't match a registered cell type:

```swift
// Unrecognized input returns false
func test_orchestrator_canHandle_false() {
    let orch = MitosisOrchestrator()
    let result = orch.canHandle("random unrelated text about weather")
    XCTAssertFalse(result)
}

// Known input returns true
func test_orchestrator_canHandle_true() {
    let orch = MitosisOrchestrator()
    let result = orch.canHandle("epinephrine dose for cardiac arrest")
    XCTAssertTrue(result)
}

// Unrecognized input throws cellNotFound
func test_orchestrator_execute_throwsForUnknownInput() async {
    let orch = MitosisOrchestrator()
    do {
        _ = try await orch.execute(input: "random text about gardening")
        XCTFail("Should throw cellNotFound")
    } catch {
        let desc = error.localizedDescription
        XCTAssertTrue(desc.contains("No matching cell") || desc.contains("cell"))
    }
}

// matchingCellType returns nil for no match
func test_orchestrator_matchingCellType_nil() {
    let orch = MitosisOrchestrator()
    let cellType = orch.matchingCellType(for: "what is the weather today")
    XCTAssertNil(cellType)
}

// Stats for unknown types return nil
func test_orchestrator_getCellStatistics_nil() {
    let orch = MitosisOrchestrator()
    let stats = orch.getCellStatistics(cellType: "nonexistent_type")
    XCTAssertNil(stats)
}
```

Security principle: The orchestrator acts as a whitelist. Only pre-registered cell types with matching triggers can execute. This prevents arbitrary code paths from being activated by user input.

Screen reading captures whatever is on screen -- including malicious text from websites. Your data models must store it inertly:

```swift
// XSS and SQL injection in window content stored as plain text
func test_security_maliciousTextInWindowContent() {
    let malicious = "<script>alert('xss')</script> DROP TABLE users; --"
    let content = WindowContent(title: malicious, textContent: malicious, uiElements: [], appName: "Evil App")
    XCTAssertEqual(content.title, malicious)      // Stored as-is
    XCTAssertEqual(content.textContent, malicious) // Not sanitized at storage layer
}

// Extremely long text should not cause crash or truncation at model layer
func test_security_extremelyLongTextContent() {
    let hugeText = String(repeating: "A", count: 500_000)
    let content = WindowContent(title: "Big Window", textContent: hugeText, uiElements: [], appName: "App")
    XCTAssertEqual(content.textContent.count, 500_000)
}

// Empty strings must not crash summary generation
func test_security_emptyStringsHandled() {
    let context = ScreenContext(
        app: AppInfo(name: "", bundleIdentifier: "", isActive: false),
        window: WindowContent(title: "", textContent: "", uiElements: [], appName: ""),
        contextType: .unknown,
        timestamp: Date()
    )
    let _ = context.summary  // Must not crash
}
```

The principle: data models are inert storage. Sanitization happens at the boundary where data flows into prompts or UI rendering -- never at the storage layer, because you'd lose the original data.

Summary generation takes raw screen data and produces a natural language string for LLM context. Each app type needs specific formatting:

```swift
