Password field protection is a hard security boundary that must never be bypassed, regardless of safety level. This is a P0 test:

```swift
// Password fields ALWAYS denied, even in autonomous mode
func test_security_safety_secureTextFieldAlwaysDenied() {
    let safety = ScreenSafety(level: .autonomous)  // Most permissive mode
    let action = ScreenAction.typeText("hunter2", target: .role("AXSecureTextField", label: "Password"))
    let context = ScreenSafetyContext(appName: "Safari", appBundleID: "com.apple.Safari")
    let decision = safety.shouldAllow(action: action, context: context)
    if case .deny(let reason) = decision {
        XCTAssertTrue(reason.contains("password") || reason.contains("secure"))
    } else {
        XCTFail("Password fields must be denied even in autonomous mode")
    }
}

// Strict mode requires confirmation for ALL actions
func test_security_safety_strictConfirmsAllActions() {
    let safety = ScreenSafety(level: .strict)
    let context = ScreenSafetyContext(appName: "Terminal", appBundleID: "com.apple.Terminal")
    let actions: [ScreenAction] = [
        .click(target: .label("OK")),
        .typeText("hello", target: .label("Input")),
        .scroll(direction: .down, amount: 1),
        .keyboardShortcut(key: .c, modifiers: [.command]),
        .drag(from: .zero, to: CGPoint(x: 100, y: 100)),
        .selectMenuItem(path: ["File", "Quit"]),
    ]
    for action in actions {
        let decision = safety.shouldAllow(action: action, context: context)
        if case .confirm = decision {
            // expected
        } else {
            XCTFail("Strict mode must confirm all actions, failed for: \(action.type)")
        }
    }
}

// Sensitive financial content detection
func test_safety_paymentFormDetected() {
    let safety = ScreenSafety(level: .strict)
    let screenText = ["Card Number", "CVV", "Expiration Date", "Submit Payment"]
    XCTAssertTrue(safety.containsSensitiveContent(screenText: screenText))
}

func test_safety_normalFormNotSensitive() {
    let safety = ScreenSafety(level: .strict)
    let screenText = ["First Name", "Last Name", "Email", "Submit"]
    XCTAssertFalse(safety.containsSensitiveContent(screenText: screenText))
}
```

The password field test is the most critical. The detection is based on the accessibility role `AXSecureTextField`, which macOS assigns to password inputs. This cannot be spoofed by the webpage.

Review this screen agent code:
```swift
let agent = ScreenAgent()
let request = ScreenRequest(intent: "click button", targetApp: nil, actions: [
    .click(target: .label("Delete Everything"))
])
let result = await agent.execute(request: request)
```
Is this safe?

No. In strict safety mode (the default), executing an action without a confirmation handler should be denied. The agent must require human confirmation before performing destructive screen actions.

Here's the red test:

```swift
func test_security_screenAgent_deniesWithoutConfirmationHandler() async {
    let agent = ScreenAgent()
    let request = ScreenRequest(intent: "click button", targetApp: nil, actions: [
        .click(target: .label("Delete Everything"))
    ])
    let result = await agent.execute(request: request)
    // Without a confirmation handler, strict mode should deny
    XCTAssertFalse(result.success)
    XCTAssertTrue(
        result.description.contains("confirmation") ||
        result.description.contains("denied") ||
        result.description.lowercased().contains("no confirmation")
    )
}
```

The fix is to require a `confirmationHandler` closure that presents a dialog to the user before any action executes in strict mode. The default `ScreenAgent()` has no handler, so it must fail-closed (deny by default).

Also verify the agent's default config:
```swift
func test_screenAgent_configDefaults() async {
    let agent = ScreenAgent()
    let config = await agent.getConfig()
    XCTAssertEqual(config.safetyLevel, .strict)  // Default must be strict
    XCTAssertEqual(config.maxRetries, 1)          // Limit retry attempts
    XCTAssertEqual(config.actionTimeout, 5.0)     // Actions timeout quickly
}
```

FieldMapper takes untrusted input (form field labels from screen OCR) and maps them to fact keys in your personal data store. Three injection vectors to test:

```swift
// SQL injection in field labels must return nil (no mapping)
func test_security_fieldMapper_injectionPayloadsReturnNil() {
    let mapper = FieldMapper()
    XCTAssertNil(mapper.mapFieldToFact(label: "'; DROP TABLE users; --"))
    XCTAssertNil(mapper.mapFieldToFact(label: "<script>alert('xss')</script>"))
    XCTAssertNil(mapper.mapFieldToFact(label: "../../../etc/passwd"))
}

// Unknown fields must return nil, not a guess
func test_fieldMapper_unknownField() {
    let mapper = FieldMapper()
    XCTAssertNil(mapper.mapFieldToFact(label: "Favorite Color"))
    XCTAssertNil(mapper.mapFieldToFact(label: "Comments"))
}
```

The FieldMapper should use an explicit allowlist of known patterns, never fuzzy matching that could be tricked.

Null bytes in action targets are a real concern because C-based string APIs (used internally by macOS accessibility) truncate at null bytes, which could cause a label mismatch:

```swift
func test_security_actionTarget_nullByteStripped() {
    let target = ActionTarget.label("Submit\0malicious")
    XCTAssertNotNil(target.normalizedLabel)
    // The label should not silently truncate at null byte
    XCTAssertTrue(target.normalizedLabel!.contains("malicious"))
}
```

If `normalizedLabel` only returns "submit" (truncated at the null byte), an attacker could craft a label like `"OK\0DeleteAllFiles"` that appears to match a benign button but actually targets a destructive one.

The fix: Strip null bytes during normalization with `label.replacingOccurrences(of: "\0", with: "")` before lowercasing and trimming.

Financial data detection is critical because the screen agent must refuse to interact with payment forms automatically. Test multiple variants:

```swift
func test_security_safety_creditCardDetected() {
    let safety = ScreenSafety(level: .strict)
    XCTAssertTrue(safety.containsSensitiveContent(screenText: ["Credit Card"]))
    XCTAssertTrue(safety.containsSensitiveContent(screenText: ["SSN"]))
    XCTAssertTrue(safety.containsSensitiveContent(screenText: ["Routing Number"]))
    XCTAssertTrue(safety.containsSensitiveContent(screenText: ["Social Security"]))
}

// Audit log tracks all actions and decisions
func test_safety_auditLogRecords() {
    var safety = ScreenSafety(level: .strict)
    let action = ScreenAction.click(target: .label("OK"))
    safety.recordAction(action, decision: .allow, success: true)
    XCTAssertEqual(safety.auditLog.count, 1)
    XCTAssertTrue(safety.auditLog[0].success)
}

// Audit log prunes to prevent memory exhaustion
func test_safety_auditLogPrunes() {
    var safety = ScreenSafety(level: .strict, maxAuditEntries: 3)
    for i in 0..<5 {
        let action = ScreenAction.click(target: .label("Button \(i)"))
        safety.recordAction(action, decision: .allow, success: true)
    }
    XCTAssertEqual(safety.auditLog.count, 3)  // Pruned to max
}
```

The audit log pruning test is often overlooked -- without it, a long-running session accumulates unbounded audit entries.

The GapDetector identifies topics where the AI has low confidence and schedules research jobs. Sensitive topics must be excluded from this pipeline -- you don't want the system researching "my password reset" or "credit card numbers".

```swift
func test_gapDetector_addGap_excludesSensitiveTopics() async {
    let dataStore = try! DataStore()
    let detector = GapDetector(dataStore: dataStore)

    let sensitiveTopics = [
        "my password reset",
        "credit card numbers",
        "social security number",
        "private information"
    ]

    for topic in sensitiveTopics {
        let gap = KnowledgeGap(topic: topic, frequency: 1, avgConfidence: 0.3, messageIDs: [])
        await detector.addGap(gap)
    }

    let allGaps = await detector.getAllGaps()
    XCTAssertEqual(allGaps.count, 0, "Sensitive topics should be excluded")
}
```

This is a data exfiltration defense. Without this filter, a user asking about their password could trigger a web search for "user password reset" which leaks context to external search engines. The exclusion list should include: password, credit card, SSN, social security, bank account, routing number, private, secret, and similar PII-adjacent terms.

Priority sorting determines which knowledge gaps get researched first. The formula is `frequency * (1 - confidence)` -- high frequency + low confidence = highest priority. Confidence thresholds gate what gets auto-created vs discarded.

```swift
// Priority sorting: highest priority first
func test_gapDetector_getGapsByPriority_sortedCorrectly() async {
    let dataStore = try! DataStore()
    let detector = GapDetector(dataStore: dataStore)

    // priority = 2 * (1 - 0.3) = 1.4
    await detector.addGap(KnowledgeGap(topic: "topic_high", frequency: 2, avgConfidence: 0.3, messageIDs: []))
    // priority = 1 * (1 - 0.5) = 0.5
    await detector.addGap(KnowledgeGap(topic: "topic_low", frequency: 1, avgConfidence: 0.5, messageIDs: []))
    // priority = 3 * (1 - 0.2) = 2.4
    await detector.addGap(KnowledgeGap(topic: "topic_highest", frequency: 3, avgConfidence: 0.2, messageIDs: []))

    let sorted = await detector.getGapsByPriority()
    XCTAssertEqual(sorted[0].topic, "topic_highest")
    XCTAssertEqual(sorted[1].topic, "topic_high")
    XCTAssertEqual(sorted[2].topic, "topic_low")
}

// Confidence thresholds
func test_confidenceThresholds_values() {
    XCTAssertEqual(ConfidenceThresholds.minimum, 0.5)
    XCTAssertEqual(ConfidenceThresholds.autoCreate, 0.7)
    XCTAssertTrue(ConfidenceThresholds.minimum < ConfidenceThresholds.autoCreate)
}

func test_confidenceThresholds_shouldDiscard() {
    XCTAssertTrue(ConfidenceThresholds.shouldDiscard(0.3))   // Below minimum
    XCTAssertTrue(ConfidenceThresholds.shouldDiscard(0.49))  // Below minimum
    XCTAssertFalse(ConfidenceThresholds.shouldDiscard(0.5))  // At minimum
    XCTAssertFalse(ConfidenceThresholds.shouldDiscard(0.8))  // Above autoCreate
}
```

Security implication: If priority sorting is wrong, low-quality gaps could be researched first, wasting API calls and potentially fetching irrelevant or misleading information.

The coordinator is the control plane for autonomous knowledge expansion. Key security properties: (1) it must not log when disabled, (2) it must start with zero state, (3) reset must clear everything.

```swift
// Initial stats are zero
func test_coordinator_initialStats() async {
    let dataStore = try! DataStore()
    let coordinator = DomainExpansionCoordinator(dataStore: dataStore, llmEngine: nil)
    let stats = await coordinator.getStatistics()
    XCTAssertEqual(stats.gapsDetected, 0)
    XCTAssertEqual(stats.gapsResearched, 0)
    XCTAssertEqual(stats.knowledgeCreated, 0)
    XCTAssertNil(stats.lastExpansionRun)
}

// Low confidence query increments gap count
func test_coordinator_logLowConfidenceQuery_incrementsGaps() async {
    let dataStore = try! DataStore()
    let coordinator = DomainExpansionCoordinator(dataStore: dataStore, llmEngine: nil)
    await coordinator.logLowConfidenceQuery(
        query: "explain quantum entanglement",
        response: "I'm not sure...",
        confidence: 0.3
    )
    let stats = await coordinator.getStatistics()
    XCTAssertEqual(stats.gapsDetected, 1)
}

// CRITICAL: Disabled coordinator must not log
func test_coordinator_logLowConfidenceQuery_disabledNoop() async {
    let dataStore = try! DataStore()
    let coordinator = DomainExpansionCoordinator(dataStore: dataStore, llmEngine: nil)
    await coordinator.setEnabled(false)
    await coordinator.logLowConfidenceQuery(
        query: "what is dark energy",
        response: "Unknown",
        confidence: 0.2
    )
    let stats = await coordinator.getStatistics()
    XCTAssertEqual(stats.gapsDetected, 0, "Should not log when disabled")
}
```

The disabled check is a privacy boundary. When a user disables domain expansion, they're saying "don't learn from my queries." If the coordinator continues logging low-confidence queries while disabled, it's:

1. **Privacy violation**: Recording query topics the user asked to not be tracked
2. **Data accumulation**: Building a profile of the user's knowledge gaps without consent
3. **Potential exfiltration**: Those gaps could later trigger web searches when re-enabled

The test also validates the reset path:

```swift
func test_coordinator_reset() async {
    let dataStore = try! DataStore()
    let coordinator = DomainExpansionCoordinator(dataStore: dataStore, llmEngine: nil)
    await coordinator.logLowConfidenceQuery(
        query: "what is dark matter", response: "I think...", confidence: 0.3
    )
    await coordinator.reset()
    let stats = await coordinator.getStatistics()
    XCTAssertEqual(stats.gapsDetected, 0)
    XCTAssertNil(stats.lastExpansionRun)
}
```

Reset is the user's right-to-be-forgotten for the knowledge expansion system. It must clear ALL state, not just the gap count.

Intent detection false positives are a security concern because they can trigger unauthorized tool calls. The detector must be silent on non-actionable input:

```swift
// Nil for conversational text
func test_detectIntent_nilForConversation() {
    let result = sut.detectIntent(from: "How are you doing today?")
    XCTAssertNil(result, "Conversational input should not trigger any intent")
}

// Nil for empty string
func test_detectIntent_nilForEmptyString() {
    let result = sut.detectIntent(from: "")
    XCTAssertNil(result, "Empty string should not trigger any intent")
}

// Nil for whitespace
func test_detectIntent_nilForWhitespace() {
    let result = sut.detectIntent(from: "   ")
    XCTAssertNil(result, "Whitespace-only input should not trigger any intent")
}

// Email addresses should NOT be captured as URLs
func test_detectIntent_openURL_doesNotCaptureEmail() {
    let result = sut.detectIntent(from: "send email to test@example.com")
    if case .openURL = result {
        XCTFail("Email address should not trigger openURL intent")
    }
}

// Long input should NOT trigger reminder (prevents false positives from pasted docs)
func test_detectIntent_createReminder_longInputIgnored() {
    let longInput = "remind me " + String(repeating: "a", count: 300)
    let result = sut.detectIntent(from: longInput)
    if case .createReminder = result {
        XCTFail("Long input should not trigger reminder intent")
    }
}
```

The long input test is particularly important. Without the 300-char guard, pasting a document that starts with "remind me" would create a reminder with the entire document as the title.

Intent priority is critical because many phrases match multiple patterns. Wrong ordering means wrong tool calls:

```swift
// Email should take priority over URL detection
func test_detectIntent_emailBeforeURL() {
    let result = sut.detectIntent(from: "email john@example.com")
    guard case .composeEmail = result else {
        XCTFail("Email detection should take priority over URL detection, got \(String(describing: result))")
        return
    }
}

// Reminder should take priority over calendar
func test_detectIntent_reminderBeforeCalendar() {
    let result = sut.detectIntent(from: "remind me about the meeting")
    guard case .createReminder = result else {
        XCTFail("Reminder should take priority over calendar, got \(String(describing: result))")
        return
    }
}

// "don't forget" is a reminder, NOT a forgetMemory command
func test_detectIntent_forgetMemory_dontForgetIsNotForget() {
    let result = sut.detectIntent(from: "don't forget to call mom")
    if case .forgetMemory = result {
        XCTFail("'don't forget' should NOT trigger forgetMemory intent")
    }
}

// Case insensitive matching
func test_detectIntent_caseInsensitive() {
    let upper = sut.detectIntent(from: "OPEN SAFARI")
    let lower = sut.detectIntent(from: "open safari")
    guard case .launchApp = upper, case .launchApp = lower else {
        XCTFail("Intent detection should be case insensitive")
        return
    }
}
```

The "don't forget" test catches a dangerous bug: if the word "forget" triggers the memory deletion intent, a user saying "don't forget to pick up the kids" would delete memories instead of creating a reminder. Intent ordering must check negation prefixes before matching keywords.

URL detection needs careful handling because it intersects with email detection and must not execute on partial matches:

```swift
// Domain with TLD gets https:// prepended
func test_detectIntent_openURL_domainWithTLD() {
    let result = sut.detectIntent(from: "google.com")
    guard case .openURL(let url) = result else {
        XCTFail("Expected openURL intent")
        return
    }
    XCTAssertTrue(url.contains("google.com"))
    XCTAssertTrue(url.hasPrefix("https://"), "URL should have https prefix added")
}

// Explicit HTTPS preserved as-is
func test_detectIntent_openURL_explicitHTTPS() {
    let result = sut.detectIntent(from: "https://example.com")
    guard case .openURL(let url) = result else {
        XCTFail("Expected openURL intent")
        return
    }
    XCTAssertEqual(url, "https://example.com")
}

// Standalone email address triggers composeEmail, not openURL
func test_detectIntent_composeEmail_standaloneAddress() {
    let result = sut.detectIntent(from: "john@example.com")
    guard case .composeEmail(let to, _, _) = result else {
        XCTFail("Expected composeEmail for standalone email")
        return
    }
    XCTAssertEqual(to, "john@example.com")
}

// App launch filters non-app words
func test_detectIntent_launchApp_filtersNonAppWords() {
    let result = sut.detectIntent(from: "open it")
    if case .launchApp = result {
        XCTFail("'open it' should not trigger launchApp")
    }
}
```

Security note: The HTTPS prefix addition is important -- without it, `google.com` could resolve as a relative path or trigger unexpected behavior in URL handlers. Always default to HTTPS.

AppToolHandler controls which applications get launched on the user's machine. This is a P0 security boundary:

```swift
// Unknown action returns error
func test_appToolHandler_unknownAction_fails() async {
    let handler = AppToolHandler()
    let result = await handler.execute(action: "reboot", params: [:])
    XCTAssertFalse(result.success)
    XCTAssertTrue(result.error?.contains("Unknown app action") ?? false)
}

// Empty app name fails
func test_appToolHandler_launch_emptyName_fails() async {
    let handler = AppToolHandler()
    let result = await handler.execute(action: "launch", params: ["app_name": ""])
    XCTAssertFalse(result.success)
    XCTAssertTrue(result.error?.contains("Could not find or launch") ?? false)
}

// Nonexistent app fails
func test_appToolHandler_launch_nonexistentApp_fails() async {
    let handler = AppToolHandler()
    let result = await handler.execute(action: "launch", params: ["app_name": "ZZZNonExistentAppXYZ12345"])
    XCTAssertFalse(result.success)
}

// Case-insensitive lookup for mapped apps
func test_appToolHandler_launch_caseInsensitive() async {
    let handler = AppToolHandler()
    let result = await handler.execute(action: "launch", params: ["app_name": "finder"])
    XCTAssertTrue(result.success)
}

// list_active limits to 15 apps max (prevents information leakage)
func test_appToolHandler_listActive_limitsTo15() async {
    let handler = AppToolHandler()
    let result = await handler.execute(action: "list_active", params: [:])
    let appLines = result.output.components(separatedBy: "\n").filter { $0.hasPrefix("- ") }
    XCTAssertLessThanOrEqual(appLines.count, 15)
}

// Quit nonexistent app reports not running (doesn't crash)
func test_appToolHandler_quit_notRunning_fails() async {
    let handler = AppToolHandler()
    let result = await handler.execute(action: "quit", params: ["app_name": "ZZZNonExistentAppXYZ12345"])
    XCTAssertFalse(result.success)
