}
```

The 15-app limit on `list_active` prevents an LLM from enumerating all running processes on the user's machine, which could leak sensitive info about what the user is doing.

The ExecutiveToolHandler is a general-purpose tool that handles date/time queries and unknown operations. The unknown operation path is tricky -- it echoes the operation name back, which could be an XSS/injection vector if the output goes to a web view:

```swift
// Unknown operation echoes back the name (verify it's safe text)
func test_executive_unknownOperation_returnsAcknowledgement() async {
    let handler = ExecutiveToolHandler()
    let result = await handler.execute(
        action: nil,
        params: ["operation": "fire_missiles", "role": "admin"]
    )
    XCTAssertTrue(result.success)
    XCTAssertTrue(result.output.contains("fire_missiles"))
    XCTAssertTrue(result.output.contains("admin"))
}

// Missing operation defaults to "unknown" (not nil crash)
func test_executive_missingOperation_usesDefault() async {
    let handler = ExecutiveToolHandler()
    let result = await handler.execute(action: nil, params: [:])
    XCTAssertTrue(result.success)
    XCTAssertTrue(result.output.contains("unknown"))
}

// Operation matching is case-insensitive
func test_executive_operationCaseInsensitive() async {
    let handler = ExecutiveToolHandler()
    let result = await handler.execute(action: nil, params: ["operation": "GET_DATE"])
    XCTAssertTrue(result.success)
    XCTAssertTrue(result.output.hasPrefix("Today is"))
}

// No error field on success
func test_executive_noErrorOnSuccess() async {
    let handler = ExecutiveToolHandler()
    let result = await handler.execute(action: nil, params: ["operation": "get_date"])
    XCTAssertNil(result.error)
}
```

Security note: The echo-back of operation names means an attacker could craft `operation: "<img src=x onerror=alert(1)>"` and if the output renders in a WebView, that's XSS. The ToolResult output should be treated as plain text at the rendering layer.

