JSON-RPC over stdio uses line-delimited JSON. Each message must end with a newline and contain the correct protocol version:

```swift
// Version is always 2.0
func test_jsonRPCRequest_encodesCorrectVersion() throws {
    let request = JSONRPCRequest(id: 1, method: "initialize")
    XCTAssertEqual(request.jsonrpc, "2.0")
}

// Line-delimited JSON must end with newline
func test_jsonRPCRequest_encodesToLineWithNewline() throws {
    let request = JSONRPCRequest(id: 1, method: "ping")
    let data = try request.encodeToLine()
    let text = String(data: data, encoding: .utf8)!
    XCTAssertTrue(text.hasSuffix("\n"), "Line-delimited JSON must end with newline")
}

// Notifications must NOT have an id field
func test_jsonRPCNotification_hasNoId() throws {
    let notification = JSONRPCNotification(method: "notifications/initialized")
    let data = try JSONEncoder().encode(notification)
    let dict = try JSONSerialization.jsonObject(with: data) as! [String: Any]
    XCTAssertNil(dict["id"], "Notifications must not have an id field")
}

// Nil params should not encode as non-null
func test_jsonRPCRequest_nilParamsOmitted() throws {
    let request = JSONRPCRequest(id: 1, method: "ping")
    let data = try JSONEncoder().encode(request)
    let dict = try JSONSerialization.jsonObject(with: data) as! [String: Any]
    let hasNonNullParams = dict["params"] != nil && !(dict["params"] is NSNull)
    if hasNonNullParams {
        XCTFail("Nil params should not encode as non-null value")
    }
}
```

The newline termination test is critical for stdio transport. Without the trailing newline, the receiving process can't know when a message ends, leading to buffer hangs or partial reads.

