Division by zero in analytics calculations produces NaN/Infinity, which breaks JSON serialization and downstream dashboards:

```swift
func test_dashboardSnapshot_zeroValues_noNaN() {
    let snapshot = DashboardSnapshot(
        date: Date(),
        mrr: 0, totalInstalls: 0, activeTrials: 0,
        trialConversionRate: 0, churnRate: 0, dau: 0, wau: 0,
        avgSessionDuration: 0, toolUsageBreakdown: [:],
        paywallConversionRate: 0, avgLLMResponseTime: 0,
        avgRTAIResponseTime: 0, tcaEngagementRate: 0,
        topPaywallTrigger: "none", crashCount: 0
    )

    let dict = snapshot.toDictionary()
    for (key, value) in dict {
        if let doubleVal = value as? Double {
            XCTAssertFalse(doubleVal.isNaN, "\(key) should not be NaN")
            XCTAssertFalse(doubleVal.isInfinite, "\(key) should not be infinite")
        }
    }
}

// Date is ISO8601 format
func test_dashboardSnapshot_dateIsISO8601() {
    let snapshot = DashboardSnapshot(
        date: Date(), mrr: 0, totalInstalls: 0, activeTrials: 0,
        trialConversionRate: 0, churnRate: 0, dau: 0, wau: 0,
        avgSessionDuration: 0, toolUsageBreakdown: [:],
        paywallConversionRate: 0, avgLLMResponseTime: 0,
        avgRTAIResponseTime: 0, tcaEngagementRate: 0,
        topPaywallTrigger: "none", crashCount: 0
