    XCTAssertNotNil(result)
    XCTAssertEqual(result?.resolution, .autoResolveExisting)
}

// Similar confidence -> requires user resolution
func test_contradiction_closeConfidence_needsUserResolution() async {
    let result = await contradictionDetector.detect(
        newKey: "wife's name",
        newValue: "Sarah",
        newConfidence: 0.8,
        existingFacts: ["wife's name": (value: "Christina", confidence: 0.75)]
    )
    XCTAssertNotNil(result)
    XCTAssertEqual(result?.resolution, .needsUserResolution)
}

// Same value = no contradiction regardless of confidence
func test_contradiction_sameKeySameValue_noContradiction() async {
    let result = await contradictionDetector.detect(
        newKey: "wife's name",
        newValue: "Christina",
        newConfidence: 0.9,
        existingFacts: ["wife's name": (value: "Christina", confidence: 0.8)]
