}
```

The threshold between auto-resolve and user-resolution should be around 0.3 confidence difference. Too low and you auto-resolve things the user should decide; too high and you pester them with obvious corrections.

The BehavioralPatternEngine learns from user interactions and predicts next actions. Security concern: predictions influence proactive AI behavior, so false predictions could trigger unwanted actions.

```swift
@MainActor
final class BehavioralPatternEngineRedTests: XCTestCase {
    private var engine: BehavioralPatternEngine!

    override func setUp() {
        engine = BehavioralPatternEngine.shared
        engine.resetForTesting()  // Clean state for each test
    }

    override func tearDown() {
        engine.resetForTesting()  // Prevent cross-test contamination
    }

    private func makeDate(hour: Int) -> Date {
        let calendar = Calendar.current
        var components = calendar.dateComponents([.year, .month, .day], from: Date())
        components.hour = hour
        components.minute = 0
        components.second = 0
        return calendar.date(from: components)!
    }

    // 5 observations at hour 10 -> predict check_email at hour 10
    func test_observeAction_updatesPatternsForPrediction() {
        let targetDate = makeDate(hour: 10)
        for _ in 0..<5 {
            engine.observeInteraction(UserInteraction(timestamp: targetDate, action: "check_email", context: [:]))
        }
        let prediction = engine.predictNextAction(currentTime: targetDate)
        XCTAssertNotNil(prediction)
        XCTAssertEqual(prediction?.action, "check_email")
    }

    // Morning vs evening: correct action at each time
    func test_temporalPrediction_predictsActionAtCorrectHour() {
        let morningDate = makeDate(hour: 8)
        let eveningDate = makeDate(hour: 20)
        for _ in 0..<10 {
            engine.observeInteraction(UserInteraction(timestamp: morningDate, action: "morning_routine", context: [:]))
            engine.observeInteraction(UserInteraction(timestamp: eveningDate, action: "evening_routine", context: [:]))
        }
        XCTAssertEqual(engine.predictNextAction(currentTime: morningDate)?.action, "morning_routine")
        XCTAssertEqual(engine.predictNextAction(currentTime: eveningDate)?.action, "evening_routine")
    }
}
```

The `resetForTesting()` in setUp/tearDown is critical -- without it, tests contaminate each other and you get flaky results.

Without a minimum confidence threshold, the engine would suggest actions based on a single observation, leading to noisy and potentially annoying proactive suggestions:

```swift
// Single observation at a distant hour should yield nil or very low confidence
func test_minimumConfidence_singleObservationReturnsNil() {
    let observeDate = makeDate(hour: 3)
    engine.observeInteraction(UserInteraction(timestamp: observeDate, action: "rare_action", context: [:]))

    // Predict at hour 16 (far from observed hour)
    let predictDate = makeDate(hour: 16)
    let prediction = engine.predictNextAction(currentTime: predictDate)

    if let prediction = prediction {
        XCTAssertLessThanOrEqual(prediction.confidence, 0.3,
            "Single observation at distant hour should yield confidence <= 0.3")
    }
    // nil is also acceptable
}

// Multiple suggestions sorted by confidence descending
func test_multipleSuggestions_returnsSortedByConfidence() {
    let date = makeDate(hour: 11)
    for _ in 0..<12 { engine.observeInteraction(UserInteraction(timestamp: date, action: "strong_action", context: [:])) }
    for _ in 0..<6 { engine.observeInteraction(UserInteraction(timestamp: date, action: "medium_action", context: [:])) }
    for _ in 0..<3 { engine.observeInteraction(UserInteraction(timestamp: date, action: "weak_action", context: [:])) }

    let suggestions = engine.getProactiveSuggestions(currentTime: date, topN: 3)
    XCTAssertGreaterThanOrEqual(suggestions.count, 2)

    for i in 0..<(suggestions.count - 1) {
        XCTAssertGreaterThanOrEqual(suggestions[i].confidence, suggestions[i + 1].confidence,
            "Suggestions should be sorted by confidence descending")
    }
}
```

The 0.3 confidence threshold prevents the engine from suggesting "rare_action" to the user just because they did it once at 3 AM. Proactive suggestions should only fire when there's strong evidence of a pattern.

Sequential and contextual prediction are powerful features that need careful testing to avoid false triggers:

```swift
// A->B pattern: after observing open_app -> check_messages 10x,
// predict check_messages after open_app
func test_sequentialPrediction_predictsNextActionInSequence() {
    let date = makeDate(hour: 12)
    for _ in 0..<10 {
        engine.observeInteraction(UserInteraction(timestamp: date, action: "open_app", context: [:]))
        engine.observeInteraction(UserInteraction(timestamp: date, action: "check_messages", context: [:]))
    }
    let prediction = engine.predictNextAction(currentTime: date, recentAction: "open_app")
    XCTAssertNotNil(prediction)
    XCTAssertEqual(prediction?.action, "check_messages")
}

// Context differentiation: work context -> code_review, home -> play_music
func test_contextualPrediction_predictsBasedOnContext() {
    let date = makeDate(hour: 12)
    for _ in 0..<8 {
        engine.observeInteraction(UserInteraction(timestamp: date, action: "code_review", context: ["location": "work"]))
    }
    for _ in 0..<8 {
        engine.observeInteraction(UserInteraction(timestamp: date, action: "play_music", context: ["location": "home"]))
    }
    let workPrediction = engine.predictNextAction(currentTime: date, context: ["location": "work"])
    let homePrediction = engine.predictNextAction(currentTime: date, context: ["location": "home"])
    XCTAssertEqual(workPrediction?.action, "code_review")
    XCTAssertEqual(homePrediction?.action, "play_music")
}
```

The TCA (Temporal-Contextual-Activity) formula combines three signals. The prediction must include a score breakdown for transparency and debugging:

```swift
func test_tcaWeightedFormula_includesScoreBreakdown() {
    let date = makeDate(hour: 14)
    for _ in 0..<8 {
        engine.observeInteraction(UserInteraction(timestamp: date, action: "write_code", context: ["app": "xcode"]))
    }
    let prediction = engine.predictNextAction(currentTime: date, context: ["app": "xcode"])

    XCTAssertNotNil(prediction)
    XCTAssertNotNil(prediction?.scores, "Prediction should include PredictionScores breakdown")

    if let scores = prediction?.scores {
        XCTAssertGreaterThan(scores.temporal, 0, "Temporal score should be > 0 at observed hour")
        XCTAssertGreaterThan(scores.frequency, 0, "Frequency score should be > 0")
        XCTAssertGreaterThan(scores.contextual, 0, "Contextual score should be > 0 with matching context")
    }
}
```

The score breakdown is important for two reasons:
1. **Debugging**: When a prediction is wrong, you can see which signal was misleading
2. **Explainability**: The proactive UI can show "Based on your usual routine at this time" (temporal) vs "Since you're in Xcode" (contextual)

All three scores must be > 0 when the context, time, and frequency all match. If any is 0, it means that signal is being dropped from the calculation.

Recency decay (0.95 per observation) ensures the engine adapts to changing behavior. Without it, old patterns dominate forever:

```swift
func test_recencyDecay_newerPatternsWin() {
    let date = makeDate(hour: 15)

    // Old action: 20 observations (heavily decayed)
    for _ in 0..<20 {
        engine.observeInteraction(UserInteraction(timestamp: date, action: "old_action", context: [:]))
    }

    // New action: 15 observations (less decayed, more recent)
    for _ in 0..<15 {
        engine.observeInteraction(UserInteraction(timestamp: date, action: "new_action", context: [:]))
    }

    let suggestions = engine.getProactiveSuggestions(currentTime: date, topN: 5)
    XCTAssertFalse(suggestions.isEmpty)

    let actions = suggestions.map { $0.action }
    // Both should appear since they have significant observations
    XCTAssertTrue(actions.contains("old_action") && actions.contains("new_action"),
        "Both old and new actions should appear in suggestions")
}

// Learned patterns require 3+ observations (5 raw due to decay)
func test_learnedPatterns_createdAfterThreeObservations() {
    let targetHour = 9
    let date = makeDate(hour: targetHour)
    for _ in 0..<5 {
        engine.observeInteraction(UserInteraction(timestamp: date, action: "standup_meeting", context: [:]))
    }
    let patterns = engine.getLearnedPatterns()
    XCTAssertFalse(patterns.isEmpty)
    let standupPattern = patterns.first { $0.action == "standup_meeting" && $0.typicalHour == targetHour }
    XCTAssertNotNil(standupPattern)
}
```

The 0.95 decay factor means after 20 observations, the effective weight of the first observation is 0.95^19 = 0.377. This gives newer patterns a real chance to compete while still respecting established habits. The 5-observation minimum (yielding ~3.0 effective weight after decay) prevents ephemeral actions from becoming learned patterns.

The complexity detector routes queries to different inference modes (instant vs deep reasoning). Wrong routing wastes resources (deep reasoning for "hi") or gives poor answers (instant mode for complex analysis):

```swift
// Short queries don't need reasoning
func test_queryComplexity_shortQueryNoReasoning() {
    XCTAssertFalse(QueryComplexityDetector.requiresReasoning("hi"))
}

// Greetings don't need reasoning
func test_queryComplexity_greetingsNoReasoning() {
    XCTAssertFalse(QueryComplexityDetector.requiresReasoning("hello"))
    XCTAssertFalse(QueryComplexityDetector.requiresReasoning("good morning"))
    XCTAssertFalse(QueryComplexityDetector.requiresReasoning("thanks"))
    XCTAssertFalse(QueryComplexityDetector.requiresReasoning("bye"))
}

// Planning and comparison queries need reasoning
func test_queryComplexity_planningRequiresReasoning() {
    XCTAssertTrue(QueryComplexityDetector.requiresReasoning("help me plan a vacation to Japan"))
    XCTAssertTrue(QueryComplexityDetector.requiresReasoning("compare React vs Vue for a new web project"))
    XCTAssertTrue(QueryComplexityDetector.requiresReasoning("explain how neural networks learn from data"))
}

// Code queries need reasoning
func test_queryComplexity_codeRequiresReasoning() {
    XCTAssertTrue(QueryComplexityDetector.requiresReasoning("review this code and find any bugs"))
    XCTAssertTrue(QueryComplexityDetector.requiresReasoning("debug this function that keeps crashing"))
}

// Long queries (12+ words) need reasoning
func test_queryComplexity_longQueriesRequireReasoning() {
    let longQuery = "I need help understanding how to implement a binary search tree in Swift with proper balancing"
    XCTAssertTrue(QueryComplexityDetector.requiresReasoning(longQuery))
}

// Simple factual queries don't need reasoning
func test_queryComplexity_simpleFactsNoReasoning() {
    XCTAssertFalse(QueryComplexityDetector.requiresReasoning("what time is it"))
    XCTAssertFalse(QueryComplexityDetector.requiresReasoning("what's 2+2"))
}
```

Resource implication: Deep reasoning uses the thinking model (business tier only, higher GPU cost). Mis-routing a simple greeting to deep reasoning wastes GPU cycles and adds latency.

Review this FTAI parser code:
```swift
func lookupQuery(_ query: String) -> String? {
    // Parse user query and look up in FTAI knowledge base
    return ftaiContent[query]
}
```
What's the security concern?

The concern is that the parser should reject certain query patterns that indicate the user is asking for help, not looking up FTAI data. Without this filter, a general help request could return raw FTAI content that wasn't meant for the user.

Here's the red test:

```swift
// Help-indicating queries should be rejected
func test_swiftFTAIParser_lookupQueryRejectsHelp() {
    let result = SwiftFTAIParser.shared.lookupQuery("help me build a website")
    XCTAssertNil(result)
}

// Non-existent keys return nil (not empty string or crash)
func test_swiftFTAIParser_lookupExactMiss() {
    let result = SwiftFTAIParser.shared.lookupExact("completely_nonexistent_key_xyz_123")
    XCTAssertNil(result)
}

// Garbage substring search returns empty
func test_swiftFTAIParser_searchKeysNoMatch() {
    let results = SwiftFTAIParser.shared.searchKeys(containing: "zzz_nonexistent_zzz")
    XCTAssertTrue(results.isEmpty)
}

// Debug logging is gated behind feature flag
func test_swiftFTAIParser_debugLoggingGated() {
    XCTAssertTrue(SwiftFTAIParser.inlineDebugLoggingIsGated)
}
```

The debug logging gate is also important -- FTAI content may contain sensitive project data, and logging it to the console in production would be an information leak. The gate ensures logging only happens when `DebugSettings.fileLoggingEnabled` is explicitly on.

AnalyzedContext assembles screen data with memory and contact context for the LLM. Each component must be represented in the summary:

```swift
// Basic summary includes app name
func test_analyzedContext_naturalLanguageSummary_basic() {
    let screen = ScreenContext(
        app: AppInfo(name: "Safari", bundleIdentifier: "com.apple.Safari", isActive: true),
        window: nil, contextType: .browser(url: nil), timestamp: Date()
    )
    let analyzed = AnalyzedContext(
        screenContext: screen, recognizedContacts: [],
        relevantMemories: [], suggestions: [], analyzedAt: Date()
    )
    XCTAssertTrue(analyzed.naturalLanguageSummary.contains("Safari"))
}

// Recognized contacts include name and relationship
func test_analyzedContext_naturalLanguageSummary_withContacts() {
    let screen = ScreenContext(
        app: AppInfo(name: "Mail", bundleIdentifier: "com.apple.mail", isActive: true),
        window: nil, contextType: .email(nil), timestamp: Date()
    )
    let contact = RecognizedContact(
        identifier: "john@test.com", name: "John Smith",
        memoryContext: "Project lead for Alpha", relationship: "colleague"
    )
    let analyzed = AnalyzedContext(
        screenContext: screen, recognizedContacts: [contact],
        relevantMemories: [], suggestions: [], analyzedAt: Date()
    )
    XCTAssertTrue(analyzed.naturalLanguageSummary.contains("John Smith"))
    XCTAssertTrue(analyzed.naturalLanguageSummary.contains("colleague"))
}

// Relevant memories included
func test_analyzedContext_naturalLanguageSummary_withMemories() {
    let screen = ScreenContext(
        app: AppInfo(name: "Notes", bundleIdentifier: "com.apple.Notes", isActive: true),
        window: nil, contextType: .notes, timestamp: Date()
    )
    let analyzed = AnalyzedContext(
        screenContext: screen, recognizedContacts: [],
        relevantMemories: ["User prefers dark mode", "Weekly review on Fridays"],
        suggestions: [], analyzedAt: Date()
    )
    XCTAssertTrue(analyzed.naturalLanguageSummary.contains("Related info I remember"))
    XCTAssertTrue(analyzed.naturalLanguageSummary.contains("dark mode"))
}

// Suggestions appear in summary
func test_analyzedContext_naturalLanguageSummary_withSuggestion() {
    let screen = ScreenContext(
        app: AppInfo(name: "Xcode", bundleIdentifier: "com.apple.dt.Xcode", isActive: true),
        window: nil, contextType: .coding, timestamp: Date()
    )
    let suggestion = ContextSuggestion(type: .offer, text: "I can help explain this code", action: "ask_about_code")
    let analyzed = AnalyzedContext(
        screenContext: screen, recognizedContacts: [],
        relevantMemories: [], suggestions: [suggestion], analyzedAt: Date()
    )
    XCTAssertTrue(analyzed.naturalLanguageSummary.contains("I can help explain this code"))
}
```

Security note: The summary flows directly into the LLM context. Contact names and memory content from the user's data are injected here -- they must be in a clearly labeled section so the LLM doesn't confuse user data with system instructions (prompt injection defense).

The FeatureFlagManager controls which ML backend (MLX, CoreML, or auto) handles inference. Wrong resolution can crash the app or produce garbage output:

```swift
// Default backend should be .mlx
func test_featureFlagManager_defaultBackend() {
    FeatureFlagManager.shared.resetToDefaults()
    XCTAssertEqual(FeatureFlagManager.shared.selectedBackend, .mlx)
}

// .mlx always resolves to .mlx
func test_featureFlagManager_resolveMLX() {
    FeatureFlagManager.shared.selectedBackend = .mlx
    let resolved = FeatureFlagManager.shared.resolveBackend()
    XCTAssertEqual(resolved, .mlx)
}

// CoreML without ANE falls back to MLX (prevents crash on non-ANE hardware)
func test_featureFlagManager_coreMLFallsBackWithoutANE() {
    FeatureFlagManager.shared.selectedBackend = .coreML
    FeatureFlagManager.shared.isANEEnabled = false
    let resolved = FeatureFlagManager.shared.resolveBackend()
    XCTAssertEqual(resolved, .mlx)  // Fallback
    FeatureFlagManager.shared.resetToDefaults()
}

// enableANEForTesting sets all required flags
func test_featureFlagManager_enableANEForTesting() {
    FeatureFlagManager.shared.enableANEForTesting()
    XCTAssertTrue(FeatureFlagManager.shared.isANEEnabled)
    XCTAssertEqual(FeatureFlagManager.shared.selectedBackend, .coreML)
    XCTAssertTrue(FeatureFlagManager.shared.isBenchmarkMode)
    FeatureFlagManager.shared.resetToDefaults()
}

// Configuration snapshot has all expected keys
func test_featureFlagManager_getCurrentConfiguration() {
    let config = FeatureFlagManager.shared.getCurrentConfiguration()
    XCTAssertNotNil(config["backend"])
    XCTAssertNotNil(config["aneEnabled"])
    XCTAssertNotNil(config["resolvedBackend"])
}

// Apple Silicon detection
func test_featureFlagManager_hasNeuralEngine() {
    #if arch(arm64)
    XCTAssertTrue(FeatureFlagManager.shared.hasNeuralEngine())
    #else
    XCTAssertFalse(FeatureFlagManager.shared.hasNeuralEngine())
    #endif
}
```

The CoreML fallback test is the most critical. Without the ANE check, selecting CoreML on hardware without a Neural Engine would cause a runtime crash when the model tries to compile for a non-existent accelerator. The fallback to MLX ensures graceful degradation.
